#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int ones=0, b;
        for(int i=0;i<N;i++){
            scanf("%d", &b);
            if(b) ones++;
        }
        if(ones<=N && ((N-ones)&1)==0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

